"use client";
import {
  AutocompleteSearch,
  type AutocompleteOption,
} from "@/components/ui/autocomplete-search";

async function searchUsers(query: string): Promise<AutocompleteOption[]> {
  const res = await fetch(`/api/users?q=${encodeURIComponent(query)}`);
  if (!res.ok) throw new Error("request failed");
  const users = (await res.json()) as { id: string; name: string; email: string }[];
  return users.map((u) => ({ value: u.id, label: u.name, description: u.email }));
}

export default function UserSearch() {
  return (
    <AutocompleteSearch
      onSearch={searchUsers}
      minChars={2}
      placeholder="Search users…"
      hintMessage="Type at least 2 characters"
      emptyMessage="No users match that search"
    />
  );
}
